export type ActType =
  | "legge"
  | "decreto-legge"
  | "decreto-legislativo"
  | "codice"
  | "regolamento"
  | "trattato-ue"
  | "altro";

export type VersionStatus = "vigente" | "abrogata" | "originaria" | "storica";

export type StructuralUnitType = "articolo" | "comma" | "lettera" | "capo" | "titolo";

export type ReferenceType = "rinvio" | "modifica" | "abrogazione" | "recepimento-ue";

export type ReferenceExtractionSource = "akn-ref" | "testo-regex";

export type ReferenceResolutionStatus = "risolto" | "esterno" | "pendente";

export interface Norma {
  eli: string;
  tipoAtto: ActType;
  numero: string;
  data: string;
  titolo: string;
  fonte: string;
}

export interface Versione {
  id: string;
  normaEli: string;
  vigenzaDa: string;
  vigenzaA?: string;
  stato: VersionStatus;
}

export interface Manifestazione {
  id: string;
  versioneId: string;
  formato: "akn+xml" | "xml-nir" | "html" | "pdf" | "testo";
  urlFonte: string;
  sha256: string;
}

export interface ItemFonte {
  id: string;
  manifestazioneId: string;
  storageUri?: string;
  acquisitoIl?: string;
  dimensioneByte: number;
}

export interface Unita {
  id: string;
  versioneId: string;
  tipo: StructuralUnitType;
  numero: string;
  percorso: string;
  testo: string;
  eliUnita?: string;
}

export interface CitationMetadata {
  eli: string;
  fonte: string;
  tipoAtto: ActType;
  numeroAtto: string;
  dataAtto: string;
  articolo: string;
  comma?: string;
  vigenzaDa: string;
  vigenzaA?: string;
  urlFonte?: string;
  idArtefattoFonte?: string;
}

export interface Chunk {
  id: string;
  unitaId: string;
  testo: string;
  embedding?: readonly number[];
  metadati: CitationMetadata;
}

export interface Riferimento {
  daEli: string;
  aEli: string;
  tipo: ReferenceType;
  fonteEstrazione?: ReferenceExtractionSource;
  testoMatch?: string;
  confidenza?: number;
}

export interface CitationValidationResult {
  valid: boolean;
  missingFields: readonly string[];
}

export class CitationMetadataError extends Error {
  constructor(public readonly missingFields: readonly string[]) {
    super(`Metadati di citazione obbligatori mancanti: ${missingFields.join(", ")}`);
    this.name = "CitationMetadataError";
  }
}

const REQUIRED_CITATION_FIELDS = [
  "eli",
  "fonte",
  "tipoAtto",
  "numeroAtto",
  "dataAtto",
  "articolo",
  "vigenzaDa"
] as const;

export function validateCitationMetadata(
  metadata: Partial<CitationMetadata>
): CitationValidationResult {
  const missingFields = REQUIRED_CITATION_FIELDS.filter((field) => {
    const value = metadata[field];
    return typeof value !== "string" || value.trim().length === 0;
  });

  if (!metadata.urlFonte && !metadata.idArtefattoFonte) {
    return {
      valid: false,
      missingFields: [...missingFields, "urlFonte|idArtefattoFonte"]
    };
  }

  return {
    valid: missingFields.length === 0,
    missingFields
  };
}

export function assertCitationMetadata(
  metadata: Partial<CitationMetadata>
): asserts metadata is CitationMetadata {
  const result = validateCitationMetadata(metadata);

  if (!result.valid) {
    throw new CitationMetadataError(result.missingFields);
  }
}

export function createChunk(input: {
  id: string;
  unitaId: string;
  testo: string;
  embedding?: readonly number[];
  metadati: Partial<CitationMetadata>;
}): Chunk {
  assertCitationMetadata(input.metadati);

  return {
    id: input.id,
    unitaId: input.unitaId,
    testo: input.testo,
    embedding: input.embedding,
    metadati: input.metadati
  };
}

export function createCitationLabel(metadata: CitationMetadata): string {
  const comma = metadata.comma ? `, comma ${metadata.comma}` : "";
  const validity = metadata.vigenzaA
    ? `vigente dal ${metadata.vigenzaDa} al ${metadata.vigenzaA}`
    : `vigente dal ${metadata.vigenzaDa}`;
  const tipoAtto = formatActTypeForLabel(metadata);

  return `${tipoAtto} ${metadata.numeroAtto}/${metadata.dataAtto}, art. ${metadata.articolo}${comma} (${validity})`;
}

function formatActTypeForLabel(metadata: CitationMetadata): string {
  if (metadata.eli.includes("/regio-decreto/")) {
    return "regio decreto";
  }

  if (metadata.eli.includes("/decreto-legislativo/")) {
    return "decreto legislativo";
  }

  if (metadata.eli.includes("/decreto-legge/")) {
    return "decreto legge";
  }

  if (metadata.tipoAtto === "trattato-ue" || metadata.eli.includes("/treaty/")) {
    return "trattato UE";
  }

  return metadata.tipoAtto;
}

export function isVersionActiveAt(versione: Versione, date: string): boolean {
  if (date < versione.vigenzaDa) {
    return false;
  }

  if (versione.vigenzaA && date > versione.vigenzaA) {
    return false;
  }

  return true;
}
