import { createHash } from "node:crypto";
import { mkdir, writeFile } from "node:fs/promises";
import { dirname, join } from "node:path";
import { PutObjectCommand, S3Client } from "@aws-sdk/client-s3";
import type { CorpusNormativo, DocumentoFonteOriginale } from "./index";

export interface OggettoArchiviato {
  bucket?: string;
  chiave: string;
  dimensioneByte: number;
  sha256: string;
  uri: string;
}

export interface SalvaArtefattoInput {
  body: string | Buffer;
  bucket?: string;
  chiave: string;
  contentType: string;
  metadati?: Record<string, string>;
}

export interface ArchiviazioneOggetti {
  salvaArtefatto(input: SalvaArtefattoInput): Promise<OggettoArchiviato>;
}

export interface FileSystemObjectStorageOptions {
  baseDir: string;
}

export class FileSystemObjectStorage implements ArchiviazioneOggetti {
  constructor(private readonly options: FileSystemObjectStorageOptions) {}

  async salvaArtefatto(input: SalvaArtefattoInput): Promise<OggettoArchiviato> {
    const percorso = join(this.options.baseDir, input.chiave);
    const body = Buffer.isBuffer(input.body) ? input.body : Buffer.from(input.body, "utf8");

    await mkdir(dirname(percorso), { recursive: true });
    await writeFile(percorso, body);

    return {
      chiave: input.chiave,
      dimensioneByte: body.byteLength,
      sha256: sha256(body),
      uri: `file://${percorso.replaceAll("\\", "/")}`
    };
  }
}

export interface S3ObjectStorageOptions {
  accessKeyId: string;
  bucket: string;
  endpoint?: string;
  forcePathStyle?: boolean;
  region: string;
  secretAccessKey: string;
}

export class S3ObjectStorage implements ArchiviazioneOggetti {
  private readonly client: S3Client;

  constructor(private readonly options: S3ObjectStorageOptions) {
    this.client = new S3Client({
      credentials: {
        accessKeyId: options.accessKeyId,
        secretAccessKey: options.secretAccessKey
      },
      endpoint: options.endpoint,
      forcePathStyle: options.forcePathStyle ?? true,
      region: options.region
    });
  }

  async salvaArtefatto(input: SalvaArtefattoInput): Promise<OggettoArchiviato> {
    const body = Buffer.isBuffer(input.body) ? input.body : Buffer.from(input.body, "utf8");
    const bucket = input.bucket ?? this.options.bucket;

    await this.client.send(
      new PutObjectCommand({
        Body: body,
        Bucket: bucket,
        ContentType: input.contentType,
        Key: input.chiave,
        Metadata: {
          sha256: sha256(body),
          ...(input.metadati ?? {})
        }
      })
    );

    return {
      bucket,
      chiave: input.chiave,
      dimensioneByte: body.byteLength,
      sha256: sha256(body),
      uri: `s3://${bucket}/${input.chiave}`
    };
  }
}

export function creaArchiviazioneOggettiDaEnv(
  env: NodeJS.ProcessEnv = process.env
): ArchiviazioneOggetti {
  const driver = env.OBJECT_STORAGE_DRIVER ?? "file";

  if (driver === "s3") {
    return new S3ObjectStorage({
      accessKeyId: requireEnv(env, "S3_ACCESS_KEY_ID"),
      bucket: requireEnv(env, "S3_BUCKET"),
      endpoint: env.S3_ENDPOINT,
      forcePathStyle: true,
      region: env.S3_REGION ?? "local",
      secretAccessKey: requireEnv(env, "S3_SECRET_ACCESS_KEY")
    });
  }

  return new FileSystemObjectStorage({
    baseDir: env.OBJECT_STORAGE_DIR ?? "artifacts/storage"
  });
}

export async function archiviaFontiCorpus(
  corpus: CorpusNormativo,
  storage: ArchiviazioneOggetti
): Promise<OggettoArchiviato[]> {
  const risultati: OggettoArchiviato[] = [];

  for (const documento of corpus.documentiFonte) {
    risultati.push(await archiviaDocumentoFonte(documento, storage));
  }

  return risultati;
}

async function archiviaDocumentoFonte(
  documento: DocumentoFonteOriginale,
  storage: ArchiviazioneOggetti
): Promise<OggettoArchiviato> {
  return storage.salvaArtefatto({
    body: documento.contenuto,
    chiave: `fonti/${documento.nomeFile}`,
    contentType: documento.contentType,
    metadati: {
      artefatto: documento.artefatto.id,
      fonte: documento.artefatto.fonte
    }
  });
}

function requireEnv(env: NodeJS.ProcessEnv, key: string): string {
  const value = env[key];

  if (!value) {
    throw new Error(`Variabile d'ambiente obbligatoria mancante: ${key}`);
  }

  return value;
}

function sha256(body: Buffer): string {
  return createHash("sha256").update(body).digest("hex");
}
